"""Extractor: reads CSV files and parses records.

Handles encoding, date parsing, and basic field validation.
Outputs a list of dicts with normalized field names.
"""

import csv
import io
from datetime import datetime


def parse_date(date_str):
    """Parse an ISO-8601 date string, handling UTC 'Z' suffix.

    Returns a datetime object.  UTC timestamps (ending in 'Z') are
    parsed as timezone-aware datetimes.
    """
    if not date_str:
        return None
    date_str = date_str.strip()
    # BUG 1: strips 'Z' but does NOT set tzinfo=timezone.utc.
    # This produces a naive datetime that raises TypeError when compared
    # with a timezone-aware datetime reference downstream.
    if date_str.endswith('Z'):
        date_str = date_str[:-1]  # remove Z, forget to mark as UTC
    try:
        return datetime.fromisoformat(date_str)
    except ValueError:
        return None


def read_csv(content, encoding='utf-8'):
    """Parse CSV text into a list of row dicts.

    Numeric fields (amount, quantity, price, unit_price, tax_rate) are
    cast to float.  The 'date' field is parsed by parse_date.
    """
    numeric_fields = {'amount', 'quantity', 'price', 'unit_price', 'tax_rate'}
    reader = csv.DictReader(io.StringIO(content))
    records = []
    for row in reader:
        record = {}
        for key, value in row.items():
            key = key.strip()
            value = value.strip() if value else ''
            if key in numeric_fields:
                try:
                    record[key] = float(value)
                except (ValueError, TypeError):
                    record[key] = 0.0
            elif key == 'date':
                record[key] = parse_date(value)
            else:
                record[key] = value
        records.append(record)
    return records


def validate_record(record):
    """Return True if the record has required fields with valid values."""
    for field in ('customer_id', 'product_id', 'amount', 'date'):
        if field not in record:
            return False
    if record.get('amount', 0) < 0:
        return False
    return True


def extract(content, encoding='utf-8'):
    """Full extract step: parse CSV, validate, return clean records."""
    records = read_csv(content, encoding=encoding)
    return [r for r in records if validate_record(r)]

