"""Pipeline: orchestrates Extract -> Transform -> Load.

Manages errors and generates a summary report after processing.
"""

import io
from etl.extractor import extract
from etl.transformer import transform
from etl.loader import Loader


class Pipeline:
    """Full ETL pipeline: Extract -> Transform -> Load."""

    def __init__(self, batch_size=10):
        self.loader = Loader(batch_size=batch_size)
        self.processed = []
        self.errors = []

    def run(self, csv_content, output=None):
        """Run the full pipeline on CSV text content.

        Returns dict with keys 'records', 'output', 'summary'.
        """
        if output is None:
            output = io.StringIO()

        try:
            extracted = extract(csv_content)
        except Exception as e:
            self.errors.append(f'extract error: {e}')
            extracted = []

        try:
            transformed = transform(extracted)
        except Exception as e:
            self.errors.append(f'transform error: {e}')
            transformed = []

        self.processed = transformed

        try:
            self.loader.write_records(transformed, output)
        except Exception as e:
            self.errors.append(f'load error: {e}')

        summary = self._generate_summary(transformed)
        return {
            'records': transformed,
            'output': output.getvalue() if hasattr(output, 'getvalue') else None,
            'summary': summary,
        }

    def _generate_summary(self, records):
        """Generate a per-category revenue summary.

        BUG 7: uses r.get('amount') (pre-tax) for 'electronics' but
        r.get('total_amount') for every other category.  The fix is to
        always use 'total_amount'.
        """
        summary = {
            'total_records': len(records),
            'revenue_by_category': {},
            'errors': list(self.errors),
        }
        for r in records:
            cat = r.get('category', 'misc')
            if cat not in summary['revenue_by_category']:
                summary['revenue_by_category'][cat] = 0.0
            # BUG 7: inconsistent field — electronics reads pre-tax 'amount'
            if cat == 'electronics':
                summary['revenue_by_category'][cat] += r.get('amount', 0.0)
            else:
                summary['revenue_by_category'][cat] += r.get('total_amount', 0.0)
        for cat in summary['revenue_by_category']:
            summary['revenue_by_category'][cat] = round(
                summary['revenue_by_category'][cat], 2
            )
        return summary

