"""Tests for the ETL transformer. DO NOT MODIFY."""
import sys, os
sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from datetime import datetime, timezone
from etl.transformer import (
    convert_currency, calculate_tax, map_category,
    deduplicate, transform,
)


# ── PASSING (2): basic sanity ─────────────────────────────────────────────────

def test_map_category_known_codes():
    """Known product-code prefixes map to the correct category names."""
    assert map_category('ELEC001') == 'electronics'
    assert map_category('BOOK999') == 'books'
    assert map_category('FOOD123') == 'food'
    assert map_category('') == 'misc'


def test_deduplicate_exact_duplicate_removed():
    """Two records identical in customer, product AND date are a true duplicate."""
    dt = datetime(2024, 1, 1, tzinfo=timezone.utc)
    records = [
        {'customer_id': 'C1', 'product_id': 'P1', 'date': dt, 'amount': 10.0},
        {'customer_id': 'C1', 'product_id': 'P1', 'date': dt, 'amount': 10.0},
    ]
    result = deduplicate(records)
    assert len(result) == 1, f"Expected 1 (true duplicate), got {len(result)}"


# ── FAILING (6): currency precision bugs ──────────────────────────────────────

def test_convert_currency_eur_precision():
    """EUR->USD must be rounded to 2 dp: 9.99 * 1.08 = 10.7892 -> 10.79."""
    assert convert_currency(9.99, 'EUR') == 10.79, (
        f"Expected 10.79, got {convert_currency(9.99, 'EUR')}"
    )


def test_convert_currency_gbp_precision():
    """GBP->USD must be rounded to 2 dp: 7.99 * 1.27 = 10.1473 -> 10.15."""
    assert convert_currency(7.99, 'GBP') == 10.15, (
        f"Expected 10.15, got {convert_currency(7.99, 'GBP')}"
    )


def test_convert_currency_no_float_drift():
    """EUR->USD must not drift: 1.49 * 1.08 = 1.6092 -> rounds to 1.61."""
    result = convert_currency(1.49, 'EUR')
    assert result == 1.61, f"Expected 1.61 (rounded), got {result}"


def test_calculate_tax_electronics_rounded():
    """Electronics tax (8%): 19.99 * 1.08 = 21.5892 -> round to 21.59."""
    assert calculate_tax(19.99, 'electronics') == 21.59, (
        f"Expected 21.59, got {calculate_tax(19.99, 'electronics')}"
    )


def test_calculate_tax_clothing_rounded():
    """Clothing tax (6%): 14.99 * 1.06 = 15.8894 -> round to 15.89."""
    assert calculate_tax(14.99, 'clothing') == 15.89, (
        f"Expected 15.89, got {calculate_tax(14.99, 'clothing')}"
    )


def test_calculate_tax_misc_rounded():
    """Misc tax (5%): 9.99 * 1.05 = 10.4895 -> round to 10.49."""
    assert calculate_tax(9.99, 'misc') == 10.49, (
        f"Expected 10.49, got {calculate_tax(9.99, 'misc')}"
    )


# ── FAILING (4): deduplication key bug ────────────────────────────────────────

def test_deduplicate_different_dates_not_deduped():
    """Same customer+product on 2 different dates must keep both records."""
    dt1 = datetime(2024, 1, 1, tzinfo=timezone.utc)
    dt2 = datetime(2024, 1, 2, tzinfo=timezone.utc)
    records = [
        {'customer_id': 'C1', 'product_id': 'P1', 'date': dt1, 'amount': 10.0},
        {'customer_id': 'C1', 'product_id': 'P1', 'date': dt2, 'amount': 15.0},
    ]
    result = deduplicate(records)
    assert len(result) == 2, (
        f"Expected 2 (different dates), got {len(result)}. "
        "Date must be part of the dedup key."
    )


def test_deduplicate_three_daily_purchases_kept():
    """Three purchases of the same product on 3 consecutive days must all be kept."""
    records = [
        {'customer_id': 'C1', 'product_id': 'ELEC001',
         'date': datetime(2024, 2, d, tzinfo=timezone.utc), 'amount': 10.0 * d}
        for d in range(1, 4)
    ]
    result = deduplicate(records)
    assert len(result) == 3, f"Expected 3 (3 different days), got {len(result)}"


def test_transform_multi_day_purchases_all_present():
    """transform() must not dedup records for the same item on different days."""
    records = [
        {'customer_id': 'C1', 'product_id': 'ELEC001', 'amount': 100.0,
         'date': datetime(2024, 1, d, tzinfo=timezone.utc), 'currency': 'USD'}
        for d in range(1, 4)
    ]
    result = transform(records)
    assert len(result) == 3, (
        f"Expected 3 (purchases on days 1-3), got {len(result)}"
    )


def test_transform_output_total_amount_rounded():
    """transform() total_amount field must be rounded to 2 decimal places."""
    records = [
        {'customer_id': 'C1', 'product_id': 'ELEC001', 'amount': 19.99,
         'date': datetime(2024, 1, 1, tzinfo=timezone.utc), 'currency': 'USD'},
    ]
    result = transform(records)
    assert len(result) == 1
    total = result[0]['total_amount']
    # 19.99 USD * 1.08 tax = 21.5892 -> must round to 21.59
    assert total == 21.59, (
        f"Expected total_amount 21.59 (rounded), got {total}. "
        "calculate_tax must round to 2 decimal places."
    )
